            "Wood": {
                "name": "Wood",
                "fieldName": "wood",
                "group": "AffinityType",
                "descriptions": ["People born to Wood tend to be patient, compassionate, and focused on growth. They value harmony and nurturing others, often acting as caretakers or guides. Their calm demeanor hides persistence; like a forest slowly overtaking stone, they endure and steadily influence the world around them.", "Wood magic nurtures and sustains life while also quietly weakening enemies. It can mend wounds, strengthen allies, or spread toxins that sap vitality. Wood also commands plants and bends the winds, allowing its bearer to guide growth, stir the air, and entangle the battlefield with living roots and leaves."],
                "variable": "Wood",
                "title": "Wood Affinity",
                "subGroup": "",
                "abbreviation": "",
                "baseFormula": "",
                "modifiers": "",
                "formula": {"formulaString": "", "workers": []},
                "linkedGroups": [],
                "isResource": ""
            },
            "WoodF": {
                "name": "WoodF",
                "fieldName": "woodf",
                "group": "AffinityTypeDesc",
                "descriptions": ["A Wood affinity grants the following:\nHP bonus equal to your Character Rank x 5.\nWillpower bonus equal to your Character Rank x 5.\nRegen Value bonus equal to 10 + your Character Rank x 10.\nEnergy Resistance bonus equal to your Potency."],
                "variable": "",
                "title": "",
                "subGroup": "",
                "abbreviation": "",
                "baseFormula": "",
                "modifiers": "",
                "formula": {"formulaString": "", "workers": []},
                "linkedGroups": [],
                "isResource": ""
            },
            "Fire": {
                "name": "Fire",
                "fieldName": "fire",
                "group": "AffinityType",
                "descriptions": ["Those born to Fire are passionate, expressive, and driven. Their emotions burn brightly, giving them confidence, ambition, and a strong desire to act. They thrive on intensity and inspiration, though their energy can sometimes become impulsive or overwhelming.", "Fire magic embodies destructive force and radiant brilliance. It commands flame and heat, allowing its bearer to ignite the battlefield and unleash waves of burning power. Fire also shapes light and molten glass, producing blinding flashes, searing beams, or razor-edged crystalline forms."],
                "variable": "Fire",
                "title": "Fire Affinity",
                "subGroup": "",
                "abbreviation": "",
                "baseFormula": "",
                "modifiers": "",
                "formula": {"formulaString": "", "workers": []},
                "linkedGroups": [],
                "isResource": ""
            },
